function New-AdmissionFixture {
    param([string]$Name,[string]$ResultId,[string]$MissionId="synthetic-transaction-$Name",[int]$PreservationPadding=0,[int]$PacketFolderPadding=40)
    $mission=Copy-Object $readMission;$mission.mission_id=$MissionId;$mission.original_request="SYNTHETIC_TRANSACTION_$Name";$mission.normalized_goal='Exercise transactional admission only.';$mission.created_at=[datetimeoffset]::UtcNow.ToString('o');$mission.expires_at=[datetimeoffset]::UtcNow.AddMinutes(30).ToString('o')
    $root=Join-Path $runtimeRoot "transactional\$Name";$queueRoot=Join-Path $root 'queue';$queuePath=Join-Path $queueRoot 'postrun_pending\m.json';$document=ConvertTo-TsfCanonicalExecutionArtifacts $mission $repo;Write-Json $document $queuePath
    $registry=Join-Path $root 'registry';Write-Json $mission (Join-Path $registry 'm.json')
    $padding=if($PreservationPadding){'p'*$PreservationPadding}else{'p'};$preservationRoot=Join-Path $root "$padding\preservation";$packetFolder=Join-Path $preservationRoot ('packet-'+'q'*$PacketFolderPadding);$packetPath=Join-Path $packetFolder 'preservation_packet.json';Write-Json ([pscustomobject]@{mission_id=$mission.mission_id;final_decision='GREEN'}) $packetPath
    $result=Copy-Object $mapperResult;$result.result_id=$ResultId;$result.mission_id=$mission.mission_id;$result.mission_revision=$mission.mission_revision;$result.mission_content_hash=Get-TsfContractJsonHash $mission;$result.policy_fingerprint=$mission.policy.fingerprint;$result.preservation_evidence.packet_path=$packetPath;$result.preservation_evidence.packet_sha256=Get-Hash $packetPath;$result.created_at=[datetimeoffset]::UtcNow.ToString('o')
    $resultPath=Join-Path $root 'result.json';Write-Json $result $resultPath;$ledger=Join-Path $root 'ledger.json';Write-Json ([pscustomobject]@{schema_version=1;ledger_id="ledger-$Name";approvals=@()}) $ledger
    [pscustomobject]@{root=$root;mission=$mission;result=$result;result_path=$resultPath;registry=$registry;queue_root=$queueRoot;queue_path=$queuePath;ledger=$ledger;preservation_root=$preservationRoot;packet_path=$packetPath}
}
