        Assert-Case 'VS-LIVE-RO-009' live_readonly ((Test-Path -LiteralPath $liveAdmissionPath)-and(Test-Path -LiteralPath $liveTransactionPath)-and((Get-Content $liveTransactionPath -Raw|ConvertFrom-Json).state-eq'COMMITTED')) 'mandatory short receipts durably committed'
        $runtimeEvidence=Get-Content $readCase.result.runtime_evidence_path -Raw|ConvertFrom-Json
        $spoofAdapter=Get-Content $runtimeEvidence.adapter_result_path -Raw|ConvertFrom-Json;$spoofAdapter.observed_model='spoofed-model';$spoofAdapterPath=Join-Path $runtimeRoot 'spoof-adapter.json';Write-Json $spoofAdapter $spoofAdapterPath;$spoofEvidence=Copy-Object $runtimeEvidence;$spoofEvidence.adapter_result_path=$spoofAdapterPath;Assert-Case 'VS-EVIDENCE-001' evidence (Throws {ConvertTo-TsfDurableResultEnvelope $readMission $spoofEvidence $repo}) 'adapter spoof rejected'
        $spoofVerifier=Get-Content $runtimeEvidence.verifier_result_path -Raw|ConvertFrom-Json;$spoofVerifier.mission_id='spoofed-mission';$spoofVerifierPath=Join-Path $runtimeRoot 'spoof-verifier.json';Write-Json $spoofVerifier $spoofVerifierPath;$verifierEvidence=Copy-Object $runtimeEvidence;$verifierEvidence.verifier_result_path=$spoofVerifierPath;Assert-Case 'VS-EVIDENCE-002' evidence (Throws {ConvertTo-TsfDurableResultEnvelope $readMission $verifierEvidence $repo}) 'verifier spoof rejected'
        $spoofPres=Get-Content $runtimeEvidence.preservation_packet_path -Raw|ConvertFrom-Json;$spoofPres.mission_id='spoofed-mission';$spoofPresPath=Join-Path $runtimeRoot 'spoof-preservation.json';Write-Json $spoofPres $spoofPresPath;$presEvidence=Copy-Object $runtimeEvidence;$presEvidence.preservation_packet_path=$spoofPresPath;Assert-Case 'VS-EVIDENCE-003' evidence (Throws {ConvertTo-TsfDurableResultEnvelope $readMission $presEvidence $repo}) 'preservation mismatch rejected'
        $registry=Join-Path $readCase.case_root 'durable_mission_registry';$resultPath=$readCase.result.durable_result_path;$originalReceiptPath=[string]$readCase.result.admission_receipt.admission_receipt_path;$originalReceiptHash=Get-Hash $originalReceiptPath;$exact=Get-TsfAdmissionDecision $resultPath $registry (Join-Path $repo 'fleet\control\policy-manifest.v1.json') $readCase.ledger $readCase.result.final_queue_mission_path $readCase.queue_root -UnsupportedDevelopmentMode;Assert-Case 'VS-REPLAY-002' replay ($exact.idempotent_replay-and$exact.status-eq'ADMITTED_WITH_CAVEATS') 'exact replay idempotent'
        $changed=Copy-Object $durable;$changed.proposed_next_action='conflicting replay';$changedPath=Join-Path $runtimeRoot 'conflicting-result.json';Write-Json $changed $changedPath;$conflict=Get-TsfAdmissionDecision $changedPath $registry (Join-Path $repo 'fleet\control\policy-manifest.v1.json') $readCase.ledger $readCase.result.final_queue_mission_path $readCase.queue_root -UnsupportedDevelopmentMode;Assert-Case 'VS-REPLAY-003' replay ($conflict.status-eq'REJECTED_INVALID_EVIDENCE'-and(Get-Hash $originalReceiptPath)-eq$originalReceiptHash-and(Test-Path -LiteralPath $conflict.conflict_receipt_path)) 'conflicting replay preserves original'
        $approvalBound=Copy-Object $readMission;$approvalBound.approval_references=@([pscustomobject]@{approval_id='approval-fixture-vertical';exact_action='local_write'});$approvalQueue=ConvertTo-TsfCanonicalExecutionArtifacts $approvalBound $repo;$approvalRoot=Join-Path $runtimeRoot 'missing-approval';$approvalQueueRoot=Join-Path $approvalRoot 'queue';$approvalQueuePath=Join-Path $approvalQueueRoot 'postrun_pending\mission.json';Write-Json $approvalQueue $approvalQueuePath;$approvalRegistry=Join-Path $approvalRoot 'registry';Write-Json $approvalBound (Join-Path $approvalRegistry 'mission.json');$approvalResult=Copy-Object $durable;$approvalResult.result_id='missing-required-approval-result';$approvalResult.mission_content_hash=Get-TsfContractJsonHash $approvalBound;$approvalResult.approval_use=@();$approvalLegacyPacket=Join-Path $approvalRoot 'preservation\packet\preservation_packet.json';Write-Json ([pscustomobject]@{mission_id=$approvalBound.mission_id;final_decision='GREEN'}) $approvalLegacyPacket;$approvalResult.preservation_evidence.packet_path=$approvalLegacyPacket;$approvalResult.preservation_evidence.packet_sha256=Get-Hash $approvalLegacyPacket;$approvalResultPath=Join-Path $approvalRoot 'result.json';Write-Json $approvalResult $approvalResultPath;$missingApproval=Get-TsfAdmissionDecision $approvalResultPath $approvalRegistry (Join-Path $repo 'fleet\control\policy-manifest.v1.json') $readCase.ledger $approvalQueuePath $approvalQueueRoot -UnsupportedDevelopmentMode;Assert-Case 'VS-APPROVAL-007' approval ($missingApproval.status-eq'TIM_REQUIRED'-and($missingApproval.reasons-join' ')-match'Every required approval') ($missingApproval.reasons-join'; ')
    }
}

if($RunLiveWorkspaceWrite-and$readGreen){
    $writeRepo=Join-Path $runtimeRoot 'workspace-write-repo';New-Item -ItemType Directory -Force (Join-Path $writeRepo 'input'),(Join-Path $writeRepo 'output')|Out-Null;Set-Content -LiteralPath (Join-Path $writeRepo 'input\source.txt') -Value 'synthetic input';& git -C $writeRepo init -q;& git -C $writeRepo config user.email 'fixture@tsf.invalid';& git -C $writeRepo config user.name 'TSF Fixture';& git -C $writeRepo add .;& git -C $writeRepo commit -q -m fixture;$writeBranch=(& git -C $writeRepo branch --show-current).Trim();$writeHead=(& git -C $writeRepo rev-parse HEAD).Trim();$writeMission=New-CanonicalMission 'synthetic-tsf-workspace-appserver-0001' $writeRepo $writeBranch $writeHead -WorkspaceWrite
    $writeCase=Invoke-LiveCase $writeMission 'workspace-write';$writeGreen=$writeCase.exit-eq0-and$null-ne$writeCase.result-and[string]$writeCase.result.final_decision-eq'GREEN';Assert-Case 'VS-LIVE-WR-001' live_workspace_write $writeGreen ($writeCase.output-join' ')
    if($writeGreen){$artifact=Join-Path $writeRepo 'output\result.txt';$adapter=Get-Content (Get-Content $writeCase.result.lifecycle_result_path -Raw|ConvertFrom-Json).adapter_result_path -Raw|ConvertFrom-Json;Assert-Case 'VS-LIVE-WR-002' live_workspace_write ((Get-Content $artifact -Raw).Trim()-eq'TSF workspace-write round trip complete.') 'exact fixture content';Assert-Case 'VS-LIVE-WR-003' live_workspace_write ($adapter.worker_tool_network_policy-eq'DISABLED'-and!$adapter.worker_network_used) 'worker network disabled';Assert-Case 'VS-LIVE-WR-004' live_workspace_write ($writeCase.result.admission_status-eq'ADMITTED_WITH_CAVEATS'-and$writeCase.result.final_queue_state-eq'complete_ready_for_gate') 'workspace admission with truthful effort caveat';Assert-Case 'VS-LIVE-WR-005' live_workspace_write ($adapter.turn_usage.evidence_classification-eq'NATIVE_OBSERVED'-and$adapter.turn_usage.total_tokens-gt0) 'workspace native usage observed';Assert-Case 'VS-LIVE-WR-006' live_workspace_write ((Test-Path -LiteralPath $writeCase.result.admission_receipt.admission_receipt_path)-and(Test-Path -LiteralPath $writeCase.result.admission_receipt.transaction_receipt_path)) 'workspace mandatory receipts persisted'}
}elseif($RunLiveWorkspaceWrite-and!$readGreen){Assert-Case 'VS-LIVE-WR-GATE' live_workspace_write $false 'read-only GREEN gate not satisfied'}

